// And groups predicates with the AND operator between them.
func And(predicates ...predicate.UpstreamKey) predicate.UpstreamKey {
	return predicate.UpstreamKey(sql.AndPredicates(predicates...))
}

// Or groups predicates with the OR operator between them.
func Or(predicates ...predicate.UpstreamKey) predicate.UpstreamKey {
	return predicate.UpstreamKey(sql.OrPredicates(predicates...))
}

// Not applies the not operator on the given predicate.
func Not(p predicate.UpstreamKey) predicate.UpstreamKey {
	return predicate.UpstreamKey(sql.NotPredicates(p))
}
